return ['messages'=>['08c43d171d235c7795ea97328bcabcac'=>'Licenciada en Sociología y doctora en Sociología por la UPV-EHU. nicia su andadura profesional como profesora de la Escuela Universitaria de Trabajo Social de Donostia-San Sebastián. A partir de ese año, profesora en la Facultad de Educación, Filosofía y Antropología de la Universidad del País Vasco EHU, impartiendo docencia en temas relacionados con el Desarrollo Comunitario, la Participación y Convivencia Ciudadanas. Vicedecana de Practicum y Cooperación, Coordinadora del Grado de Educación Social y directora del Departamento de Teoría e Historia de la Educación de la misma Facultad.','2024ko maiatzetik erretiratua, gaur egun Helduak Adi! Adinekoen Elkarteko kidea da.'=>'Jubilada desde mayo de 2024, en la actualidad es miembro de la Asociación de Personas Mayores Helduak Adi!.','5c2edbf3d55f5cc431400b7980db8c07'=>'Ha colaborado con numerosos Ayuntamientos y Equipos de Investigación.','6bdd3ac658e777f6d98846e4715bf874'=>'Jubilada desde mayo de 2024, en la actualidad es miembro de la Asociación de Personas Mayores Helduak Adi!.','Azken hamazazpi edizioetan, EHUko Adinekoei buruzko Udako Ikastaroen zuzendaria izan da.'=>'En las últimas diecisiete ediciones, Directora de Cursos de Verano de la EHU sobre Personas Mayores.','Hainbat udal eta ikerketa-talderekin lankidetzan aritu da.'=>'Ha colaborado con numerosos Ayuntamientos y Equipos de Investigación.','Soziologian lizentziatua eta Soziologian doktorea UPV-EHUn. Donostiako Gizarte Laneko Unibertsitate Eskolako irakasle gisa hasi zuen bere ibilbide profesionala. Urte horretatik aurrera, Euskal Herriko Unibertsitateko (EHU) Hezkuntza, Filosofia eta Antropologia Fakultateko irakaslea izan zen, eta Garapen Komunitarioarekin, Herritarren Partaidetzarekin eta Bizikidetzarekin lotutako gaiak irakatsi zituen. Practicum eta Lankidetzako dekanordea, Gizarte Hezkuntzako Graduko koordinatzailea eta fakultate bereko Hezkuntzaren Teoria eta Historia Saileko zuzendaria.'=>'Licenciada en Sociología y doctora en Sociología por la UPV-EHU. nicia su andadura profesional como profesora de la Escuela Universitaria de Trabajo Social de Donostia-San Sebastián. A partir de ese año, profesora en la Facultad de Educación, Filosofía y Antropología de la Universidad del País Vasco EHU, impartiendo docencia en temas relacionados con el Desarrollo Comunitario, la Participación y Convivencia Ciudadanas. Vicedecana de Practicum y Cooperación, Coordinadora del Grado de Educación Social y directora del Departamento de Teoría e Historia de la Educación de la misma Facultad.','b807c8c7fc666bdbeec72659725e2d48'=>'En las últimas diecisiete ediciones, Directora de Cursos de Verano de la EHU sobre Personas Mayores.']];
